import json
import re
from dataclasses import dataclass
from pathlib import Path
from typing import Dict, List, Optional

import torch
from peft import PeftModel
from PIL import Image
from transformers import AutoProcessor, Qwen2_5_VLForConditionalGeneration

DEFAULT_MIN_PIXELS = 256 * 28 * 28
DEFAULT_MAX_PIXELS = 512 * 28 * 28
GRID_SIZE = 1000.0


@dataclass
class ParsedPrediction:
    kind: str
    values: List[float]
    raw_text: str = ""


def _has_weights(path: Path) -> bool:
    if not path.exists() or not path.is_dir():
        return False
    names = [
        "model.safetensors",
        "model.safetensors.index.json",
        "pytorch_model.bin",
        "pytorch_model.bin.index.json",
        "model-00001-of-00002.safetensors",
        "config.json",
    ]
    return any((path / n).exists() for n in names)


def _read_meta(ckpt_dir: Path) -> Dict:
    meta_path = ckpt_dir / "meta.json"
    if meta_path.exists():
        try:
            return json.loads(meta_path.read_text())
        except Exception:
            return {}
    return {}


def resolve_base_model_dir(checkpoint: str) -> str:
    ckpt_path = Path(checkpoint).resolve()
    ckpt_dir = ckpt_path if ckpt_path.is_dir() else ckpt_path.parent
    cwd = Path.cwd().resolve()
    meta = _read_meta(ckpt_dir)

    candidates = [
        ckpt_dir / "base_model",
        ckpt_dir.parent / "base_model",
        ckpt_dir.parent / "baseline" / "base_model",
        ckpt_dir.parent.parent / "baseline" / "base_model",
        cwd / "checkpoints" / ckpt_dir.name / "base_model",
        cwd / "checkpoints" / "baseline" / "base_model",
        cwd / "checkpoints" / "base_model",
        cwd / "baseline" / "base_model",
        Path("/workspace/checkpoints") / ckpt_dir.name / "base_model",
        Path("/workspace/checkpoints/baseline/base_model"),
        Path("/workspace/checkpoints/base_model"),
        Path("/workspace/baseline/base_model"),
    ]
    for key in ["base_model_dir", "base_model", "base_dir"]:
        value = meta.get(key)
        if not value:
            continue
        p = Path(value)
        if p.is_absolute():
            candidates.append(p)
        else:
            candidates.append((ckpt_dir / p).resolve())
            candidates.append((cwd / p).resolve())

    seen = set()
    ordered = []
    for p in candidates:
        s = str(p)
        if s not in seen:
            seen.add(s)
            ordered.append(p)

    for p in ordered:
        if _has_weights(p):
            return str(p)
    raise FileNotFoundError(f"Could not find packaged base model for checkpoint {checkpoint}; tried: {[str(x) for x in ordered]}")


def load_processor(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    ckpt_dir = Path(checkpoint).resolve()
    base_dir = Path(resolve_base_model_dir(checkpoint))
    candidates = []
    if (ckpt_dir / "processor").exists():
        candidates.append(ckpt_dir / "processor")
    candidates.append(ckpt_dir)
    if (base_dir / "processor").exists():
        candidates.append(base_dir / "processor")
    candidates.append(base_dir)

    last_err = None
    for cand in candidates:
        try:
            return AutoProcessor.from_pretrained(
                str(cand),
                local_files_only=True,
                trust_remote_code=False,
                min_pixels=min_pixels,
                max_pixels=max_pixels,
            )
        except Exception as e:
            last_err = e
    raise last_err


def load_model_for_inference(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    base_dir = resolve_base_model_dir(checkpoint)
    processor = load_processor(checkpoint, min_pixels=min_pixels, max_pixels=max_pixels)
    model = Qwen2_5_VLForConditionalGeneration.from_pretrained(
        base_dir,
        torch_dtype=torch.bfloat16,
        local_files_only=True,
        trust_remote_code=False,
        device_map="auto",
    )
    ckpt_dir = Path(checkpoint).resolve()
    if (ckpt_dir / "adapter_config.json").exists():
        model = PeftModel.from_pretrained(model, str(ckpt_dir), local_files_only=True)
    model.eval()
    return model, processor


def build_messages(instruction: str):
    text = (
        "Locate the UI element described by the instruction. "
        "Reply with only one coordinate prediction on a 0-1000 grid. "
        "Preferred format: <point>x y</point>. "
        "Allowed alternatives: <box>x1 y1 x2 y2</box>, <bbox>(x1,y1),(x2,y2)</bbox>, point: x, y, or plain numbers. "
        "No explanation.\n"
        f"Instruction: {instruction}"
    )
    return [
        {
            "role": "user",
            "content": [
                {"type": "image"},
                {"type": "text", "text": text},
            ],
        }
    ]


def _extract_numbers(text: str) -> List[float]:
    return [float(x) for x in re.findall(r"-?\d+(?:\.\d+)?", text)]


def parse_prediction(raw_text: str) -> Optional[ParsedPrediction]:
    if raw_text is None:
        return None
    text = raw_text.strip()
    low = text.lower()

    patterns = [
        (r"<point>\s*([-+]?\d+(?:\.\d+)?)\s*[ ,]\s*([-+]?\d+(?:\.\d+)?)\s*</point>", "point", 2),
        (r"<point>\s*([-+]?\d+(?:\.\d+)?)\s+([-+]?\d+(?:\.\d+)?)\s*</point>", "point", 2),
        (r"point\s*[:=]?\s*\(?\s*([-+]?\d+(?:\.\d+)?)\s*[ ,]\s*([-+]?\d+(?:\.\d+)?)\s*\)?", "point", 2),
        (r"<box>\s*([-+]?\d+(?:\.\d+)?)\s*[ ,]\s*([-+]?\d+(?:\.\d+)?)\s*[ ,]\s*([-+]?\d+(?:\.\d+)?)\s*[ ,]\s*([-+]?\d+(?:\.\d+)?)\s*</box>", "bbox", 4),
        (r"<box>\s*([-+]?\d+(?:\.\d+)?)\s+([-+]?\d+(?:\.\d+)?)\s+([-+]?\d+(?:\.\d+)?)\s+([-+]?\d+(?:\.\d+)?)\s*</box>", "bbox", 4),
        (r"<bbox>\s*\(?\s*([-+]?\d+(?:\.\d+)?)\s*,\s*([-+]?\d+(?:\.\d+)?)\s*\)?\s*,\s*\(?\s*([-+]?\d+(?:\.\d+)?)\s*,\s*([-+]?\d+(?:\.\d+)?)\s*\)?\s*</bbox>", "bbox", 4),
    ]
    for pat, kind, n in patterns:
        m = re.search(pat, low, flags=re.IGNORECASE | re.DOTALL)
        if m:
            vals = [float(m.group(i + 1)) for i in range(n)]
            return ParsedPrediction(kind=kind, values=vals, raw_text=text)

    nums = _extract_numbers(text)
    if len(nums) >= 4:
        return ParsedPrediction(kind="bbox", values=nums[:4], raw_text=text)
    if len(nums) >= 2:
        return ParsedPrediction(kind="point", values=nums[:2], raw_text=text)
    return None


def clip_point(x: float, y: float, width: float, height: float) -> List[float]:
    x = max(0.0, min(float(width), float(x)))
    y = max(0.0, min(float(height), float(y)))
    return [x, y]


def clip_bbox(x1: float, y1: float, x2: float, y2: float, width: float, height: float) -> List[float]:
    xa = max(0.0, min(float(width), min(float(x1), float(x2))))
    xb = max(0.0, min(float(width), max(float(x1), float(x2))))
    ya = max(0.0, min(float(height), min(float(y1), float(y2))))
    yb = max(0.0, min(float(height), max(float(y1), float(y2))))
    return [xa, ya, xb, yb]


def _grid_to_abs(values: List[float], width: float, height: float) -> List[float]:
    out = []
    for i, v in enumerate(values):
        scale = float(width) if i % 2 == 0 else float(height)
        out.append(float(v) / GRID_SIZE * scale)
    return out


def decode_prediction(parsed: Optional[ParsedPrediction], width: float, height: float) -> Dict[str, List[float]]:
    if parsed is None:
        return {"point": [float(width) / 2.0, float(height) / 2.0]}
    if parsed.kind == "bbox" and len(parsed.values) >= 4:
        vals = _grid_to_abs(parsed.values[:4], width, height)
        bbox = clip_bbox(vals[0], vals[1], vals[2], vals[3], width, height)
        if bbox[2] <= bbox[0] or bbox[3] <= bbox[1]:
            return {"point": [float(width) / 2.0, float(height) / 2.0]}
        return {"bbox": bbox}
    vals = parsed.values[:2]
    vals = _grid_to_abs(vals, width, height)
    return {"point": clip_point(vals[0], vals[1], width, height)}


def _prepare_inputs(processor, image: Image.Image, instruction: str):
    messages = build_messages(instruction)
    text = processor.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)
    inputs = processor(text=[text], images=[image], padding=True, return_tensors="pt")
    return inputs


def generate_raw(model, processor, image: Image.Image, instruction: str, max_new_tokens: int = 16) -> str:
    image = image.convert("RGB")
    inputs = _prepare_inputs(processor, image, instruction)
    device = next(model.parameters()).device
    for k, v in list(inputs.items()):
        if isinstance(v, torch.Tensor):
            inputs[k] = v.to(device)
    with torch.no_grad():
        out = model.generate(
            **inputs,
            max_new_tokens=max_new_tokens,
            do_sample=False,
            use_cache=True,
        )
    prompt_len = inputs["input_ids"].shape[1]
    gen_ids = out[:, prompt_len:]
    text = processor.batch_decode(gen_ids, skip_special_tokens=True, clean_up_tokenization_spaces=False)[0]
    return text.strip()


def generate_prediction(model, processor, image: Image.Image, instruction: str, image_width: float, image_height: float) -> Dict[str, List[float]]:
    try:
        raw = generate_raw(model, processor, image, instruction)
        parsed = parse_prediction(raw)
        pred = decode_prediction(parsed, image_width, image_height)
        return pred
    except Exception:
        return {"point": [float(image_width) / 2.0, float(image_height) / 2.0]}
